def _bp_make_trans(objects=None):
    """Helper: create a BlueprintTransformer backed by a dict of objects."""
    objects = objects or {}

    def get_object(path, **kwargs):
        if path in objects:
            return objects[path]
        raise KeyError(path)

    return BlueprintTransformer(get_object=get_object)


