    trans = _bp_make_trans({"MyClass": cls, "MyClass:my_method": method})
    auto = Auto(name="MyClass")
    auto.children = "bad_value"
    with pytest.raises(ValueError, match="Unsupported value of children"):
        trans.visit(auto)


