def test_convert_inventory_dict(tmp_path):
    """convert_inventory writes a dict directly as JSON."""

    inv = {"project": "test", "version": "1.0", "items": []}
    out = str(tmp_path / "inv.json")
    convert_inventory(inv, out_name=out)

    with open(out) as f:
        result = json.load(f)
    assert result == inv


